func Test_ErrorEmptyBytes(t *testing.T) {
	// Graceful handling of empty bytes (should not error)
	var input xberg.ExtractInput
	if err := json.Unmarshal([]byte(`{"kind":"bytes","bytes":[],"mime_type":"text/plain","filename":"empty.txt","config":{}}`), &input); err != nil {
		t.Fatalf("config parse failed: %v", err)
	}
	_, err := xberg.Extract(input, xberg.ExtractionConfig{})
	if err != nil {
		t.Fatalf("call failed: %v", err)
	}
}

